mapper.select:
select * from pm_project_maintenance
where id = #{id}
limit 1

    select m.* from pm_project_maintenance m
        LEFT JOIN pm_project_member sm 
            ON m.`projectId` = sm.`projectId` 
            AND sm.`memberRole` = '20' 
            AND sm.`effectiveTo` IS NULL 
            AND sm.`fromFlag` = 1 
        LEFT JOIN pm_project_member pm 
            ON m.`projectId` = pm.`projectId` 
            AND pm.`memberRole` = '30' 
            AND pm.`effectiveTo` IS NULL 
            AND pm.`fromFlag` = 1 
        LEFT JOIN pm_project_member pm2 
            ON m.`projectId` = pm2.`projectId` 
            AND pm2.`memberRole` = '30' 
            AND pm2.`effectiveTo` IS NULL 
            AND pm2.`fromFlag` = 2 

        <if test=" prepend="AND" id> m.id = #{id} 
        <if test=" prepend="AND" projectId> m.projectId = #{projectId} 
        <if test=" prepend="AND" projectCode> m.projectCode like concat("%", #{projectCode}, "%") 
        <if test=" prepend="AND" projectName> m.projectName like concat("%", #{projectName}, "%") 
        <if test=" prepend="AND" projectType> m.projectType = #{projectType} 
        <if test=" prepend="AND" projectExecutionState> m.projectExecutionState = #{projectExecutionState} 
        <if test=" prepend="AND" contractNo> m.contractNo = #{contractNo} 
        <if test=" prepend="AND" officeCode> m.officeCode = #{officeCode} 
        <if test=" prepend="AND" compId> m.compId = #{compId} 
        <if test=" prepend="AND" type> m.type = #{type} 
        <if test=" prepend="AND" category> m.category = #{category} 
        <if test=" prepend="AND" subCategory> m.subCategory = #{subCategory} 
        <if test=" prepend="AND" processTime> m.processTime = #{processTime} 
        <if test=" prepend="AND" processDesc> m.processDesc = #{processDesc} 
        <if test=" prepend="AND" processStep> m.processStep = #{processStep} 
        <if test=" prepend="AND" remainProblem> m.remainProblem = #{remainProblem} 
        <if test=" prepend="AND" transitHour> m.transitHour = #{transitHour} 
        <if test=" prepend="AND" processHour> m.processHour = #{processHour} 
        <if test=" prepend="AND" itemModel> m.itemModel = #{itemModel} 
        <if test=" prepend="AND" softVersion> m.softVersion = #{softVersion} 
        <if test=" prepend="AND" enabledFeatures> m.enabledFeatures = #{enabledFeatures} 
        <if test=" prepend="AND" hasReport> m.hasReport = #{hasReport} 
        <if test=" prepend="AND" quesnaireId> m.quesnaireId = #{quesnaireId} 
        <if test=" prepend="AND" deliverFileIds> m.deliverFileIds = #{deliverFileIds} 
        <if test=" prepend="AND" remark> m.remark = #{remark} 
        <if test=" prepend="AND" createTime> m.createTime = #{createTime} 
        <if test=" prepend="AND" createBy> m.createBy = #{createBy} 
        <if test=" prepend="AND" updateTime> m.updateTime = #{updateTime} 
        <if test=" prepend="AND" updateBy> m.updateBy = #{updateBy} 

        <if test=" prepend="AND" serviceManager> sm.memberCode = #{serviceManager} 
        <if test=" prepend="AND" programManager> (pm.memberCode = #{programManager} or pm2.memberCode = #{programManager}) 

        <if test=" prepend="AND" userPower open="(" close=")">
            (m.createBy = #{userPower}
                or sm.memberCode = #{userPower} 
                or pm.memberCode = #{userPower} 
                or pm2.memberCode = #{userPower}
                <if test=" prepend="or" checkServicePower compareValue="true">
                    exists (
                       select 
                            1 
                        from
                            serviceManagerPower_$userPower$ ep 
                        where ep.serviceCode = #{userPower}
                            AND ep.programCode = m.`createBy`
                    )

            )
            <if test=" prepend="OR" areaPower> FIND_IN_SET(m.officeCode, #{areaPower})

        <if test=" userPower>
            <if test=" prepend="AND" areaPower> FIND_IN_SET(m.officeCode, #{areaPower})

        <if test=" prepend="AND" processStartTime>  m.processTime >= #{processStartTime}  
        <if test=" prepend="AND" processEndTime>  m.processTime <= #{processEndTime}  
        <if test=" prepend="AND" createStartTime>  m.createTime >= #{createStartTime}  
        <if test=" prepend="AND" createEndTime>  m.createTime <= #{createEndTime}  

        <if test=" prepend="AND" warrantyStatus> m.warrantyStatus = #{warrantyStatus} 
        <if test=" prepend="AND" industryName> m.industryName = #{industryName} 
        <if test=" prepend="AND" userOffice> m.userOffice = #{userOffice} 
        <if test=" prepend="AND" year> m.year = #{year} 
	    <if test=" prepend="AND" quarter> m.quarter = #{quarter} 
	    <if test=" prepend="AND" month> m.month = #{month} 
	    <if test=" prepend="AND" wsCount> m.wsCount = #{wsCount} 
	    <if test=" prepend="AND" wafCount> m.wafCount = #{wafCount} 
	    <if test=" prepend="AND" wsYearCount> m.wsYearCount = #{wsYearCount} 
	    <if test=" prepend="AND" wafYearCount> m.wafYearCount = #{wafYearCount} 
	    <if test=" prepend="AND" warrantyInfo> m.warrantyInfo = #{warrantyInfo} 
	    <if test=" prepend="AND" serviceInfo> m.serviceInfo = #{serviceInfo} 
	    <if test=" customInfo>

