mapper.select:
SELECT IFNULL(MAX(id), 0) maxId FROM pm_project_maintenance 
WHERE projectId = #{projectId} AND projectType = #{projectType}
GROUP BY projectType, projectId

	SELECT 
        GROUP_CONCAT(
            DISTINCT CONCAT(
                'MAX(IF(qrt.questionContent = ''', qrt.questionContent, ''', qrt.questionOptionsContent, '''')) AS `', CONCAT(
                    "questionResult", @rowNo := @rowNo + 1
                ), '`'
            )
        ) AS `columns`, COUNT(1) AS maxCount, GROUP_CONCAT(
            CONCAT("questionResult", @rowNo), "=", qrt.questionContent
        ) AS titles 
    FROM
        (SELECT DISTINCT 
            questionContent
        FROM
            $quesType$_tempQuesnaireResultLineTable

           <if test=" resultType> questionType = #{resultType} 

        ) qrt, 
        (SELECT 
            @rowNo := 0) b

    SELECT 
	    m.*, d.`departmentName` AS officeName, d2.`departmentName` AS userOfficeName, sm.`memberName` as serviceManager, pm.`memberName` as programManagerA, pm2.`memberName` as programManagerB, IFNULL(
	        CONCAT(m.createBy, "-", ui.realName), m.createBy
	    ) AS createUser, bd.`basicDataName` AS typeName, bd3.`basicDataName` AS projectExecutionStateName,
	    CONCAT(IF(m.projectType = 40, '自定义', ''), bd1.`basicDataName`) AS categoryName, bd2.`basicDataName` AS subCategoryName,
	    qrt.questionContent, qrt.questionOptionsContent,
        ff.`id` AS fileId, ff.`fileName`, ff.`filePath`,
        IFNULL(ph.column004, prh.`marketName`) AS marketName, IFNULL(ph.column005, prh.`systemName`) AS systemName, 
        IFNULL(ph.column006, prh.`expendName`) AS expendName, IFNULL(m.industryName, IFNULL(ph.column007, prh.`industryName`)) AS industryName,
        ph.column013 AS finalCustomName,
        IFNULL(prh.salesman, CONCAT(
                s.`memberCode`, "-", REPLACE(
                    s.`memberName`, CONCAT(s.`memberCode`, "-"), ""
                )
            )
        ) AS salerName, c.name as companyName, c.abbr as companyAbbr
	FROM
	    pm_project_maintenance m 
	    LEFT JOIN pm_project_header ph 
            ON m.`projectId` = ph.`projectId` 
            AND m.`projectType` = "10" 
        LEFT JOIN pm_presales_project_header prh 
            ON m.`projectId` = prh.`presalesId` 
            AND m.`projectType` = "20" 
	    LEFT JOIN pm_project_member sm 
            ON m.`projectId` = sm.`projectId` 
            AND sm.`memberRole` = '20' 
            AND sm.`effectiveTo` IS NULL 
            AND sm.`fromFlag` = 1 
	    LEFT JOIN pm_project_member pm 
	        ON m.`projectId` = pm.`projectId` 
	        AND pm.`memberRole` = '30' 
	        AND pm.`effectiveTo` IS NULL 
	        AND pm.`fromFlag` = 1 
	    LEFT JOIN pm_project_member pm2 
	        ON m.`projectId` = pm2.`projectId` 
	        AND pm2.`memberRole` = '30' 
	        AND pm2.`effectiveTo` IS NULL 
	        AND pm2.`fromFlag` = 2 
	    LEFT JOIN `pm_project_member` s 
	        ON s.`projectId` = m.`projectId` 
	        AND s.`projectType` = m.`projectType` 
	        AND m.`projectType` = "10" 
	        AND s.`memberRole` = "10" 
        AND s.`effectiveTo` IS NULL 
	    LEFT JOIN projectMaintenance_tempQuesnaireResultLineTable qrt 
            ON qrt.quesnaireResultHeaderId = m.`quesnaireId`
	    LEFT JOIN `fnd_files` ff
            ON FIND_IN_SET(ff.id, m.`deliverFileIds`)
	    LEFT JOIN `fnd_user_info` ui 
	        ON ui.`username` = m.`createBy` 
	    LEFT JOIN `fnd_basic_data` bd 
	        ON bd.`basicDataId` = m.`type` 
	        AND bd.`dataTypeCode` = 'maintenanceType' 
	    LEFT JOIN `fnd_basic_data` bd1 
            ON bd1.`basicDataId` = m.`category` 
            AND bd1.`dataTypeCode` = 'maintenanceCategory' 
        LEFT JOIN `fnd_basic_data` bd2 
            ON bd2.`basicDataId` = m.`subCategory` 
            AND bd2.`dataTypeCode` = 'maintenanceSubCategory' 
        LEFT JOIN `fnd_basic_data` bd3 
            ON bd3.`basicDataId` = m.`projectExecutionState` 
            AND bd3.`dataTypeCode` = 'projectExecutionState' 
	    LEFT JOIN fnd_department d 
	        ON d.`departmentNum` = m.`officeCode` 
	    LEFT JOIN fnd_department d2 
            ON d2.`departmentNum` = m.`userOffice` 
        LEFT JOIN fnd_company c 
            ON c.`id` = m.`compId` 

