    <if test=" prepend="AND" processEndTime>  m.processTime <= #{processEndTime}  
    <if test=" prepend="AND" createStartTime>  m.createTime >= #{createStartTime}  
    <if test=" prepend="AND" createEndTime>  m.createTime <= #{createEndTime}  




    <if test=" prepend="AND" currentTime>  m.createTime BETWEEN DATE_ADD(#{currentTime}, INTERVAL -1 DAY) AND #{currentTime}  
    <if test=" prepend="AND" currentTime>  m.createTime BETWEEN DATE_ADD(now(), INTERVAL -1 DAY) AND now()  

    <if test=" prepend="AND" warrantyStatus> m.warrantyStatus = #{warrantyStatus} 
