SELECT COUNT(distinct deliverId) = LENGTH(std.basicDataAttri1) - LENGTH(replace(std.basicDataAttri1, ",", "")) + 1 AS hasQuarterDeliveried FROM `pm_project_maintenance` m LEFT JOIN `pm_basic_deliver_detail` pd ON m.`id` = pd.projectId AND pd.`projectType` = m.`projectType` + 1 INNER JOIN `fnd_basic_data` std ON std.dataTypeCode = 'projectServiceDeliveryType' AND FIND_IN_SET(pd.deliverId, std.basicDataAttri1) WHERE m.projectId = #{projectId} AND std.basicDataId = #{serviceType} <if test=" prepend="AND" maintenanceId> m.id = #{maintenanceId} <if test=" prepend="AND" serviceDate> year(m.`processTime`) = year(IFNULL(#{serviceDate}, now())) AND quarter(m.`processTime`) = quarter(IFNULL(#{serviceDate}, now()))
<if test=" startDate> <if test=" endDate> AND m.processTime between #{startDate} and #{endDate}
GROUP BY m.`projectId`, m.projectType, dataTypeCode

select
count(deliverId) as `count`, IFNULL(sum(quarterCount), 0) totalCount, IFNULL(sum(if(year = year(IFNULL(#{serviceDate}, now())) and quarter = quarter(IFNULL(#{serviceDate}, now())), quarterCount, 0)), 0) as quarterCount from (select m.`id`, m.projectId, pd.deliverId, deliverableType, year(m.`processTime`) as year, quarter(processTime) as quarter, count(deliverId) as quarterCount from `pm_project_maintenance` m left join `fnd_basic_data` std on std.dataTypeCode = 'projectServiceDeliveryType' inner join `pm_basic_deliver_detail` pd on m.`id` = pd.projectId and pd.`projectType` = m.`projectType` + 1 and pd.deliverId = #{deliverId} where m.projectId = #{projectId} <if test=" startDate> <if test=" endDate> AND m.processTime between #{startDate} and #{endDate}
group by m.`projectId`, m.projectType, year, quarter) t

