CREATE TEMPORARY TABLE IF NOT EXISTS smDpNo_$userPower$ SELECT ui.`username` as serviceCode, ui.`realName` as serviceName, fd.`departmentNum` AS `smDpNo`, CONCAT( ui.dpNo, ",", IFNULL(up.`areapower`, '') ) AS smAreapower, fd.`departmentName` as smDpName, roleIds AS smRoleIds FROM `fnd_user_info` ui LEFT JOIN `fnd_user_power` up ON ui.`id` = up.`fndUserId` LEFT JOIN `fnd_department` fd ON fd.`isparam` and ( fd.`departmentNum` = ui.`dpNo` OR FIND_IN_SET( fd.`departmentNum`, up.`areapower` ) ) WHERE roleIds LIKE "%;11;%" ui.username = #{userPower} ;
CREATE TEMPORARY TABLE IF NOT EXISTS smAndPmDpNo_$userPower$ SELECT ui.`username` as programCode, ui.`realName` programName, fd.`departmentNum` AS `pmDpNo`, CONCAT( ui.dpNo, ",", IFNULL(up.`areapower`, '') ) AS pmAreapower, fd.`departmentName` as pmDpName, roleIds AS pmRoleIds FROM `fnd_user_info` ui LEFT JOIN `fnd_user_power` up ON ui.`id` = up.`fndUserId` LEFT JOIN `fnd_department` fd ON fd.`isparam` and ( fd.`departmentNum` = ui.`dpNo` OR FIND_IN_SET( fd.`departmentNum`, up.`areapower` ) ) WHERE ( roleIds LIKE "%;12;%" OR roleIds LIKE "%;11;%" )
;
CREATE TEMPORARY TABLE IF NOT EXISTS serviceManagerPower_$userPower$ ( key dpNo (smDpNo), key serviceCode (serviceCode, programCode), key programCode (programCode) ) SELECT * FROM smDpNo_$userPower$ sm LEFT JOIN smAndPmDpNo_$userPower$ pm ON sm.smDpNo = pm.pmDpNo
sm.serviceCode = #{userPower}
;

DROP TEMPORARY TABLE IF EXISTS smDpNo_$userPower$;
DROP TEMPORARY TABLE IF EXISTS smAndPmDpNo_$userPower$;
DROP TEMPORARY TABLE IF EXISTS serviceManagerPower_$userPower$;
